using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // -------------------------------------------------------
    // CalculateTotal — DataRow (compile-time constants)
    // -------------------------------------------------------

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.10, 0.00, DisplayName = "Zero price yields zero")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity yields zero")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "100% tax doubles subtotal")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // -------------------------------------------------------
    // CalculateTotal — DynamicData (supports decimal literals)
    // -------------------------------------------------------

    public static IEnumerable<object[]> CalculateTotalCases
    {
        get
        {
            yield return [10.00m, 1, 0.0m, 10.00m];
            yield return [10.00m, 5, 0.0m, 50.00m];
            yield return [10.00m, 1, 0.10m, 11.00m];
            yield return [25.50m, 3, 0.08m, 82.62m];
            yield return [0.01m, 100, 0.05m, 1.05m];
            yield return [999.99m, 1, 0.0m, 999.99m];
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    // -------------------------------------------------------
    // CalculateTotal — invalid-input tests
    // -------------------------------------------------------

    [TestMethod]
    [DataRow(-1.0, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativePrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.0, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.0, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.0, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // -------------------------------------------------------
    // ApplyDiscount — DataRow
    // -------------------------------------------------------

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "0% discount — full price")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off — free")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // -------------------------------------------------------
    // ApplyDiscount — DynamicData via method source
    // -------------------------------------------------------

    public static IEnumerable<object[]> GetDiscountEdgeCases()
    {
        yield return [200.00m, 33.33m, 133.34m];
        yield return [0.00m, 50.0m, 0.00m];
        yield return [1000.00m, 100.0m, 0.00m];
    }

    [TestMethod]
    [DynamicData(nameof(GetDiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithDynamicDataMethod_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    // -------------------------------------------------------
    // ApplyDiscount — invalid-input tests
    // -------------------------------------------------------

    [TestMethod]
    [DataRow(100.0, -1.0, DisplayName = "Discount below 0%")]
    [DataRow(100.0, 101.0, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidPercent_Throws(double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }

    // -------------------------------------------------------
    // FormatPrice — DataRow
    // -------------------------------------------------------

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "USD default")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(1234.5, "$", "$1234.50", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithDataRow_ReturnsExpected(
        double price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, currencySymbol);

        Assert.AreEqual(expected, result);
    }
}

